// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.sparqluo;

import static org.junit.jupiter.api.Assertions.assertEquals;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.algebra.evaluation.impl.EvaluationStatistics;
import org.junit.jupiter.api.Test;

class BeCostEstimatorSyntheticConstantPriorityTest {

	@Test
	void ignoresSyntheticConstantBindingNamesWhenEstimatingJoinSharedVars() {
		EvaluationStatistics statistics = new EvaluationStatistics() {
			@Override
			public double getCardinality(TupleExpr expr) {
				if (expr instanceof StatementPattern) {
					return 100.0d;
				}
				return super.getCardinality(expr);
			}
		};

		StatementPattern left = new StatementPattern(
				Var.of("leftS"),
				Var.of("_const_pred", SimpleValueFactory.getInstance().createIRI("urn:pLeft")),
				Var.of("leftO"));
		StatementPattern right = new StatementPattern(
				Var.of("rightS"),
				Var.of("_const_pred", SimpleValueFactory.getInstance().createIRI("urn:pRight")),
				Var.of("rightO"));

		BeTreeBuilder builder = new BeTreeBuilder(SparqlUoConfig.defaultConfig());
		BeGroupNode group = builder.build(new Join(left, right));

		BeCostEstimator estimator = new BeCostEstimator(statistics, SparqlUoConfig.builder()
				.assumedVarDomainCardinality(10.0d)
				.build());

		assertEquals(10_000.0d, estimator.estimateGroupResultSize(group), 0.0d,
				"Value-like synthetic constant names must not be treated as shared join bindings");
	}
}
